mapper.select:
select cast(od.detail_id as char) as line_key, sum(case when d.audit_status = '1' then ifnull(dd.delivery_quantity, 0) else 0 end) as audited_qty, sum(case when d.audit_status is null or d.audit_status = '0' then ifnull(dd.delivery_quantity, 0) else 0 end) as pending_qty, sum(case when d.audit_status = '2' then ifnull(dd.delivery_quantity, 0) else 0 end) as rejected_qty
where od.order_id = #{orderId}
and d.delivery_id != #{excludeDeliveryId}
group by od.detail_id


where (d.del_flag is null or d.del_flag = '' or d.del_flag = '0')
  and (
    d.zs_order_id = #{zsOrderId}
    or exists (
        select 1 from scm_delivery_detail dd
        inner join zs_tp_order_detail l on l.id = dd.zs_order_detail_id
            and (l.del_flag is null or l.del_flag = '' or l.del_flag = '0')
        where dd.delivery_id = d.delivery_id
          and l.order_id = #{zsOrderId}
          and (dd.del_flag is null or dd.del_flag = '' or dd.del_flag = '0')
    )
    or exists (
        select 1 from zs_tp_order_detail_delivery_rel r
        where r.order_id = #{zsOrderId}
          and r.delivery_id = cast(d.delivery_id as char)
    )
  )
order by d.create_time desc
